/**
 * MMS Fleet Service
 *
 * Core domain service for fleet asset management.
 * Provides CRUD operations for depots, fleets, trains, routes, and tracks.
 * Manages train lifecycle states and mileage tracking.
 *
 * Business rules:
 * - Train fitness transitions: FIT <-> RESTRICTED <-> GROUNDED
 * - Mileage accumulation is additive (never decreases except for corrections)
 * - Fleet mileage balancing: target = fleet average, variance = current - target
 * - Active entities can be deactivated but not deleted (audit compliance)
 *
 * @see specs/003-database-schema.md Section 3.2 (Core Fleet Domain)
 */

import { eq, and, inArray, sql, desc, asc, count, avg, sum, type SQL } from 'drizzle-orm';
import { BaseService, MmsAttributes } from '../lib/services/base';
import {
  depots,
  fleets,
  trains,
  routes,
  tracks,
  trainComponents,
  componentInstallations,
  componentPmTracking,
  type Depot,
  type NewDepot,
  type Fleet,
  type NewFleet,
  type Train,
  type NewTrain,
  type Route,
  type NewRoute,
  type Track,
  type NewTrack,
  type TrainComponent,
  type NewTrainComponent,
  type ComponentInstallation,
  type NewComponentInstallation,
  type ComponentPmTracking,
} from '../lib/db/schema';
import {
  NotFoundError,
  TrainNotFoundError,
  ValidationError,
  DuplicateError,
  BusinessRuleError,
} from '../lib/errors';

// =============================================================================
// Types
// =============================================================================

/** Valid fitness status transitions */
type FitnessStatus = 'FIT' | 'RESTRICTED' | 'GROUNDED';

/** Query filters for listing trains */
export interface TrainListFilters {
  fleetId?: string;
  depotId?: string;
  fitnessStatus?: FitnessStatus | FitnessStatus[];
  active?: boolean;
  trainNumbers?: string[];
}

/** Query filters for listing fleets */
export interface FleetListFilters {
  baseDepotId?: string;
  manufacturer?: string;
  active?: boolean;
}

/** Pagination options */
export interface PaginationOptions {
  page?: number;
  pageSize?: number;
  sortBy?: string;
  sortOrder?: 'asc' | 'desc';
}

/** Paginated result */
export interface PaginatedResult<T> {
  data: T[];
  total: number;
  page: number;
  pageSize: number;
  totalPages: number;
}

/** Fleet statistics */
export interface FleetStatistics {
  fleetId: string;
  fleetCode: string;
  totalTrains: number;
  activeTrains: number;
  fitTrains: number;
  restrictedTrains: number;
  groundedTrains: number;
  totalMileageKm: number;
  averageMileageKm: number;
  minMileageKm: number;
  maxMileageKm: number;
  mileageStdDevKm: number;
}

/** Train with fleet details */
export interface TrainWithFleet extends Train {
  fleet: Fleet | null;
  currentDepot: Depot | null;
  homeDepot: Depot | null;
}

/** Fitness status change request */
export interface FitnessStatusChangeRequest {
  trainId: string;
  newStatus: FitnessStatus;
  notes?: string;
  changedBy?: string;
}

/** Mileage update request */
export interface MileageUpdateRequest {
  trainId: string;
  newMileageKm: number;
  source?: string;
}

// =============================================================================
// Component Tracking Types
// =============================================================================

/** Valid component status (matches componentStatusEnum in schema) */
export type ComponentStatus = 'IN_SERVICE' | 'SPARE' | 'IN_OVERHAUL' | 'CONDEMNED';

/** Valid removal reasons (matches removalReasonEnum in schema) */
export type RemovalReason = 'SCHEDULED_OVERHAUL' | 'FAILURE' | 'SWAP' | 'UPGRADE';

/** Query filters for listing components */
export interface ComponentListFilters {
  componentType?: string;
  status?: ComponentStatus | ComponentStatus[];
  trainId?: string;
  serialNumbers?: string[];
  hasCurrentTrain?: boolean;
}

/** Component with current train details */
export interface ComponentWithTrain extends TrainComponent {
  currentTrain?: Train | null;
}

/** Component with full installation history */
export interface ComponentWithHistory extends TrainComponent {
  installations: ComponentInstallation[];
  pmTracking: ComponentPmTracking[];
}

/** Install component request */
export interface InstallComponentRequest {
  componentId: string;
  trainId: string;
  position?: string;
  workOrderId?: string;
}

/** Remove component request */
export interface RemoveComponentRequest {
  componentId: string;
  reason: RemovalReason;
  workOrderId?: string;
}

/** Transfer component request */
export interface TransferComponentRequest {
  componentId: string;
  newTrainId: string;
  newPosition?: string;
  reason?: RemovalReason;
  workOrderId?: string;
}

/** Component mileage calculation result */
export interface ComponentMileageResult {
  componentId: string;
  serialNumber: string;
  totalComponentMileageKm: number;
  installationsCalculated: number;
}

// =============================================================================
// Fleet Service
// =============================================================================

export class FleetService extends BaseService {
  constructor() {
    super({ name: 'fleet-service', version: '1.0.0' });
  }

  // ===========================================================================
  // Depot Operations
  // ===========================================================================

  async getDepotById(id: string): Promise<Depot> {
    return this.traced('getDepotById', async (span) => {
      span.setAttribute(MmsAttributes.DEPOT_ID, id);

      const result = await this.db.query.depots.findFirst({
        where: eq(depots.id, id),
      });

      if (!result) {
        throw new NotFoundError(`Depot not found: ${id}`, {
          entityType: 'depot',
          entityId: id,
        });
      }

      return result;
    });
  }

  async getDepotByCode(code: string): Promise<Depot> {
    return this.traced('getDepotByCode', async (span) => {
      span.setAttribute('depot.code', code);

      const result = await this.db.query.depots.findFirst({
        where: eq(depots.code, code),
      });

      if (!result) {
        throw new NotFoundError(`Depot not found with code: ${code}`, {
          entityType: 'depot',
          entityId: code,
        });
      }

      return result;
    });
  }

  async listDepots(options?: { active?: boolean }): Promise<Depot[]> {
    return this.traced('listDepots', async (span) => {
      const conditions: SQL<unknown>[] = [];
      if (options?.active !== undefined) {
        conditions.push(eq(depots.active, options.active));
      }

      const result = await this.db.query.depots.findMany({
        where: conditions.length > 0 ? and(...conditions) : undefined,
        orderBy: asc(depots.code),
      });

      span.setAttribute('result.count', result.length);
      return result;
    });
  }

  async createDepot(data: NewDepot): Promise<Depot> {
    return this.inTransaction('createDepot', async (tx, span) => {
      span.setAttribute('depot.code', data.code);

      // Check for duplicate code
      const existing = await tx.query.depots.findFirst({
        where: eq(depots.code, data.code),
      });

      if (existing) {
        throw new DuplicateError(`Depot with code ${data.code} already exists`, {
          field: 'code',
          value: data.code,
        });
      }

      const [result] = await tx.insert(depots).values(data).returning();
      span.setAttribute(MmsAttributes.DEPOT_ID, result.id);

      this.log.info({ depotId: result.id, code: data.code }, 'Depot created');
      return result;
    });
  }

  async updateDepot(id: string, data: Partial<NewDepot>): Promise<Depot> {
    return this.inTransaction('updateDepot', async (tx, span) => {
      span.setAttribute(MmsAttributes.DEPOT_ID, id);

      const existing = await tx.query.depots.findFirst({
        where: eq(depots.id, id),
      });

      if (!existing) {
        throw new NotFoundError(`Depot not found: ${id}`, {
          entityType: 'depot',
          entityId: id,
        });
      }

      // Check for duplicate code if changing
      if (data.code && data.code !== existing.code) {
        const duplicate = await tx.query.depots.findFirst({
          where: eq(depots.code, data.code),
        });
        if (duplicate) {
          throw new DuplicateError(`Depot with code ${data.code} already exists`, {
            field: 'code',
            value: data.code,
          });
        }
      }

      const [result] = await tx
        .update(depots)
        .set({ ...data, updatedAt: new Date() })
        .where(eq(depots.id, id))
        .returning();

      return result;
    });
  }

  async deactivateDepot(id: string): Promise<Depot> {
    return this.updateDepot(id, { active: false });
  }

  // ===========================================================================
  // Fleet Operations
  // ===========================================================================

  async getFleetById(id: string): Promise<Fleet> {
    return this.traced('getFleetById', async (span) => {
      span.setAttribute(MmsAttributes.FLEET_ID, id);

      const result = await this.db.query.fleets.findFirst({
        where: eq(fleets.id, id),
      });

      if (!result) {
        throw new NotFoundError(`Fleet not found: ${id}`, {
          entityType: 'fleet',
          entityId: id,
        });
      }

      return result;
    });
  }

  async getFleetByCode(code: string): Promise<Fleet> {
    return this.traced('getFleetByCode', async (span) => {
      span.setAttribute('fleet.code', code);

      const result = await this.db.query.fleets.findFirst({
        where: eq(fleets.code, code),
      });

      if (!result) {
        throw new NotFoundError(`Fleet not found with code: ${code}`, {
          entityType: 'fleet',
          entityId: code,
        });
      }

      return result;
    });
  }

  async listFleets(filters?: FleetListFilters): Promise<Fleet[]> {
    return this.traced('listFleets', async (span) => {
      const conditions: SQL<unknown>[] = [];

      if (filters?.baseDepotId) {
        conditions.push(eq(fleets.baseDepotId, filters.baseDepotId));
      }
      if (filters?.manufacturer) {
        conditions.push(eq(fleets.manufacturer, filters.manufacturer));
      }
      if (filters?.active !== undefined) {
        conditions.push(eq(fleets.active, filters.active));
      }

      const result = await this.db.query.fleets.findMany({
        where: conditions.length > 0 ? and(...conditions) : undefined,
        orderBy: asc(fleets.code),
      });

      span.setAttribute('result.count', result.length);
      return result;
    });
  }

  async createFleet(data: NewFleet): Promise<Fleet> {
    return this.inTransaction('createFleet', async (tx, span) => {
      span.setAttribute('fleet.code', data.code);

      // Validate base depot exists if provided
      if (data.baseDepotId) {
        const depot = await tx.query.depots.findFirst({
          where: eq(depots.id, data.baseDepotId),
        });
        if (!depot) {
          throw new ValidationError('Base depot not found', {
            field: 'baseDepotId',
            context: { depotId: data.baseDepotId },
          });
        }
      }

      // Check for duplicate code
      const existing = await tx.query.fleets.findFirst({
        where: eq(fleets.code, data.code),
      });

      if (existing) {
        throw new DuplicateError(`Fleet with code ${data.code} already exists`, {
          field: 'code',
          value: data.code,
        });
      }

      const [result] = await tx.insert(fleets).values(data).returning();
      span.setAttribute(MmsAttributes.FLEET_ID, result.id);

      this.log.info({ fleetId: result.id, code: data.code }, 'Fleet created');
      return result;
    });
  }

  async updateFleet(id: string, data: Partial<NewFleet>): Promise<Fleet> {
    return this.inTransaction('updateFleet', async (tx, span) => {
      span.setAttribute(MmsAttributes.FLEET_ID, id);

      const existing = await tx.query.fleets.findFirst({
        where: eq(fleets.id, id),
      });

      if (!existing) {
        throw new NotFoundError(`Fleet not found: ${id}`, {
          entityType: 'fleet',
          entityId: id,
        });
      }

      // Check for duplicate code if changing
      if (data.code && data.code !== existing.code) {
        const duplicate = await tx.query.fleets.findFirst({
          where: eq(fleets.code, data.code),
        });
        if (duplicate) {
          throw new DuplicateError(`Fleet with code ${data.code} already exists`, {
            field: 'code',
            value: data.code,
          });
        }
      }

      const [result] = await tx
        .update(fleets)
        .set({ ...data, updatedAt: new Date() })
        .where(eq(fleets.id, id))
        .returning();

      return result;
    });
  }

  async deactivateFleet(id: string): Promise<Fleet> {
    return this.updateFleet(id, { active: false });
  }

  // ===========================================================================
  // Train Operations
  // ===========================================================================

  async getTrainById(id: string): Promise<Train> {
    return this.traced('getTrainById', async (span) => {
      span.setAttribute(MmsAttributes.TRAIN_ID, id);

      const result = await this.db.query.trains.findFirst({
        where: eq(trains.id, id),
      });

      if (!result) {
        throw new TrainNotFoundError(id);
      }

      return result;
    });
  }

  async getTrainByNumber(trainNumber: string): Promise<Train> {
    return this.traced('getTrainByNumber', async (span) => {
      span.setAttribute(MmsAttributes.TRAIN_NUMBER, trainNumber);

      const result = await this.db.query.trains.findFirst({
        where: eq(trains.trainNumber, trainNumber),
      });

      if (!result) {
        throw new NotFoundError(`Train not found with number: ${trainNumber}`, {
          entityType: 'train',
          entityId: trainNumber,
        });
      }

      return result;
    });
  }

  async getTrainWithDetails(id: string): Promise<TrainWithFleet> {
    return this.traced('getTrainWithDetails', async (span) => {
      span.setAttribute(MmsAttributes.TRAIN_ID, id);

      const result = await this.db.query.trains.findFirst({
        where: eq(trains.id, id),
        with: {
          fleet: true,
          currentDepot: true,
          homeDepot: true,
        },
      });

      if (!result) {
        throw new TrainNotFoundError(id);
      }

      return result as TrainWithFleet;
    });
  }

  async listTrains(
    filters?: TrainListFilters,
    pagination?: PaginationOptions
  ): Promise<PaginatedResult<Train>> {
    return this.traced('listTrains', async (span) => {
      const conditions: SQL<unknown>[] = [];

      if (filters?.fleetId) {
        conditions.push(eq(trains.fleetId, filters.fleetId));
      }
      if (filters?.depotId) {
        conditions.push(eq(trains.currentDepotId, filters.depotId));
      }
      if (filters?.fitnessStatus) {
        if (Array.isArray(filters.fitnessStatus)) {
          conditions.push(inArray(trains.fitnessStatus, filters.fitnessStatus));
        } else {
          conditions.push(eq(trains.fitnessStatus, filters.fitnessStatus));
        }
      }
      if (filters?.active !== undefined) {
        conditions.push(eq(trains.active, filters.active));
      }
      if (filters?.trainNumbers && filters.trainNumbers.length > 0) {
        conditions.push(inArray(trains.trainNumber, filters.trainNumbers));
      }

      const whereClause = conditions.length > 0 ? and(...conditions) : undefined;

      // Get total count
      const [{ totalCount }] = await this.db
        .select({ totalCount: count() })
        .from(trains)
        .where(whereClause);

      // Apply pagination
      const page = pagination?.page ?? 1;
      const pageSize = Math.min(pagination?.pageSize ?? 50, 500);
      const offset = (page - 1) * pageSize;

      // Determine sort order
      const sortDirection = pagination?.sortOrder === 'desc' ? desc : asc;
      const getOrderBy = () => {
        switch (pagination?.sortBy) {
          case 'mileage':
            return sortDirection(trains.currentMileageKm);
          case 'fitnessStatus':
            return sortDirection(trains.fitnessStatus);
          default:
            return sortDirection(trains.trainNumber);
        }
      };

      const data = await this.db.query.trains.findMany({
        where: whereClause,
        orderBy: getOrderBy(),
        limit: pageSize,
        offset,
      });

      span.setAttribute('result.count', data.length);
      span.setAttribute('result.total', totalCount);

      return {
        data,
        total: totalCount,
        page,
        pageSize,
        totalPages: Math.ceil(totalCount / pageSize),
      };
    });
  }

  async createTrain(data: NewTrain): Promise<Train> {
    return this.inTransaction('createTrain', async (tx, span) => {
      span.setAttribute(MmsAttributes.TRAIN_NUMBER, data.trainNumber);

      // Validate fleet exists
      const fleet = await tx.query.fleets.findFirst({
        where: eq(fleets.id, data.fleetId),
      });
      if (!fleet) {
        throw new ValidationError('Fleet not found', {
          field: 'fleetId',
          context: { fleetId: data.fleetId },
        });
      }

      // Validate depots if provided
      if (data.currentDepotId) {
        const depot = await tx.query.depots.findFirst({
          where: eq(depots.id, data.currentDepotId),
        });
        if (!depot) {
          throw new ValidationError('Current depot not found', {
            field: 'currentDepotId',
            context: { depotId: data.currentDepotId },
          });
        }
      }

      if (data.homeDepotId) {
        const depot = await tx.query.depots.findFirst({
          where: eq(depots.id, data.homeDepotId),
        });
        if (!depot) {
          throw new ValidationError('Home depot not found', {
            field: 'homeDepotId',
            context: { depotId: data.homeDepotId },
          });
        }
      }

      // Check for duplicate train number
      const existing = await tx.query.trains.findFirst({
        where: eq(trains.trainNumber, data.trainNumber),
      });

      if (existing) {
        throw new DuplicateError(`Train with number ${data.trainNumber} already exists`, {
          field: 'trainNumber',
          value: data.trainNumber,
        });
      }

      const [result] = await tx.insert(trains).values(data).returning();
      span.setAttribute(MmsAttributes.TRAIN_ID, result.id);

      this.log.info(
        { trainId: result.id, trainNumber: data.trainNumber, fleetId: data.fleetId },
        'Train created'
      );
      return result;
    });
  }

  async updateTrain(id: string, data: Partial<NewTrain>): Promise<Train> {
    return this.inTransaction('updateTrain', async (tx, span) => {
      span.setAttribute(MmsAttributes.TRAIN_ID, id);

      const existing = await tx.query.trains.findFirst({
        where: eq(trains.id, id),
      });

      if (!existing) {
        throw new TrainNotFoundError(id);
      }

      // Check for duplicate train number if changing
      if (data.trainNumber && data.trainNumber !== existing.trainNumber) {
        const duplicate = await tx.query.trains.findFirst({
          where: eq(trains.trainNumber, data.trainNumber),
        });
        if (duplicate) {
          throw new DuplicateError(`Train with number ${data.trainNumber} already exists`, {
            field: 'trainNumber',
            value: data.trainNumber,
          });
        }
      }

      const [result] = await tx
        .update(trains)
        .set({ ...data, updatedAt: new Date() })
        .where(eq(trains.id, id))
        .returning();

      return result;
    });
  }

