   602→  /**
   603→   * Fulfill a material reservation
   604→   *
   605→   * Marks the reservation as fulfilled, indicating that the materials have been
   606→   * delivered and are ready for the PM. Optionally can specify a different fulfilled
   607→   * quantity than reserved (partial fulfillment).
   608→   *
   609→   * @param request - Fulfillment request with reservation ID
   610→   * @returns Updated reservation details
   611→   * @throws NotFoundError if reservation not found
   612→   * @throws ValidationError if already fulfilled or expired
   613→   */
   614→  async fulfillReservation(
   615→    request: FulfillReservationRequest
   616→  ): Promise<FulfillReservationResult> {
   617→    return this.traced('fulfillReservation', async (span) => {
   618→      span.setAttribute('reservation.id', request.reservationId);
   619→
   620→      const now = new Date();
   621→
   622→      // Get current reservation state
   623→      const existing = await this.db
   624→        .select()
   625→        .from(materialReservations)
   626→        .where(eq(materialReservations.id, request.reservationId))
   627→        .limit(1);
   628→
   629→      if (existing.length === 0) {
   630→        throw new NotFoundError(`Reservation not found: ${request.reservationId}`);
   631→      }
   632→
   633→      const reservation = existing[0];
   634→
   635→      // Check if already fulfilled
   636→      if (reservation.fulfilledAt) {
   637→        throw new ValidationError(
   638→          'Reservation is already fulfilled',
   639→          { context: { code: 'ALREADY_FULFILLED', reservationId: request.reservationId } }
   640→        );
   641→      }
   642→
   643→      // Check if expired
   644→      if (reservation.expiresAt && new Date(reservation.expiresAt) < now) {
   645→        throw new ValidationError(
   646→          'Cannot fulfill an expired reservation',
   647→          { context: { code: 'RESERVATION_EXPIRED', reservationId: request.reservationId } }
   648→        );
   649→      }
   650→
   651→      // Determine fulfilled quantity
   652→      const fulfilledQuantity =
   653→        request.fulfilledQuantity ?? reservation.quantityReserved;
   654→
   655→      // Update the reservation
   656→      await this.db
   657→        .update(materialReservations)
   658→        .set({
   659→          fulfilledAt: now,
   660→          fulfilledQuantity,
   661→        })
   662→        .where(eq(materialReservations.id, request.reservationId));
   663→
   664→      this.log.info(
   665→        {
   666→          reservationId: request.reservationId,
   667→          partNumber: reservation.partNumber,
   668→          quantityReserved: reservation.quantityReserved,
   669→          fulfilledQuantity,
   670→        },
   671→        'Reservation fulfilled'
   672→      );
   673→
   674→      return {
   675→        id: request.reservationId,
   676→        partNumber: reservation.partNumber,
   677→        quantityReserved: reservation.quantityReserved,
   678→        fulfilledQuantity,
   679→        fulfilledAt: now.toISOString(),
   680→        status: 'FULFILLED',
   681→      };
   682→    });
   683→  }
