   653→  /**
   654→   * Create or update a labor rate
   655→   */
   656→  async upsertLaborRate(rate: Omit<LaborRate, 'id'>): Promise<LaborRate> {
   657→    return this.traced('upsertLaborRate', async (span) => {
   658→      if (rate.depotId) {
   659→        span.setAttribute(MmsAttributes.DEPOT_ID, rate.depotId);
   660→      }
   661→
   662→      const existing = await this.db.query.laborRates.findFirst({
   663→        where: and(
   664→          rate.depotId
   665→            ? eq(laborRates.depotId, rate.depotId)
   666→            : isNull(laborRates.depotId),
   667→          eq(laborRates.effectiveFrom, rate.effectiveFrom.toISOString().split('T')[0])
   668→        ),
   669→      });
   670→
   671→      if (existing) {
   672→        const [updated] = await this.db
   673→          .update(laborRates)
   674→          .set({
   675→            regularHourlyRate: rate.regularHourlyRate.toString(),
   676→            overtimeMultiplier: rate.overtimeMultiplier.toString(),
   677→            weekendMultiplier: rate.weekendMultiplier.toString(),
   678→            holidayMultiplier: rate.holidayMultiplier.toString(),
   679→            shopRateHourly: rate.shopRateHourly.toString(),
   680→            effectiveTo: rate.effectiveTo?.toISOString().split('T')[0] || null,
   681→          })
   682→          .where(eq(laborRates.id, existing.id))
   683→          .returning();
   684→
   685→        return this.mapLaborRate(updated);
   686→      }
   687→
   688→      const [created] = await this.db
   689→        .insert(laborRates)
   690→        .values({
   691→          depotId: rate.depotId,
   692→          regularHourlyRate: rate.regularHourlyRate.toString(),
   693→          overtimeMultiplier: rate.overtimeMultiplier.toString(),
   694→          weekendMultiplier: rate.weekendMultiplier.toString(),
   695→          holidayMultiplier: rate.holidayMultiplier.toString(),
   696→          shopRateHourly: rate.shopRateHourly.toString(),
   697→          effectiveFrom: rate.effectiveFrom.toISOString().split('T')[0],
   698→          effectiveTo: rate.effectiveTo?.toISOString().split('T')[0] || null,
   699→          currency: rate.currency,
   700→        })
   701→        .returning();
   702→
   703→      return this.mapLaborRate(created);
   704→    });
   705→  }
   706→
   707→  // ===========================================================================
   708→  // Cost Baseline Methods
   709→  // ===========================================================================
   710→
   711→  /**
   712→   * Create or update a cost baseline for a fiscal year
   713→   */
   714→  async upsertCostBaseline(baseline: {
   715→    fiscalYear: number;
   716→    depotId?: string | null;
   717→    budgetLaborCost: number;
   718→    budgetMaterialCost: number;
   719→    budgetLaborHours?: number;
   720→  }): Promise<typeof costBaselines.$inferSelect> {
   721→    return this.traced('upsertCostBaseline', async (span) => {
   722→      span.setAttribute('baseline.fiscal_year', baseline.fiscalYear);
   723→      if (baseline.depotId) {
   724→        span.setAttribute(MmsAttributes.DEPOT_ID, baseline.depotId);
   725→      }
   726→
   727→      const budgetTotal = baseline.budgetLaborCost + baseline.budgetMaterialCost;
   728→
   729→      const existing = await this.db.query.costBaselines.findFirst({
   730→        where: and(
   731→          eq(costBaselines.fiscalYear, baseline.fiscalYear),
   732→          baseline.depotId
   733→            ? eq(costBaselines.depotId, baseline.depotId)
   734→            : isNull(costBaselines.depotId)
   735→        ),
   736→      });
   737→
   738→      if (existing) {
   739→        const [updated] = await this.db
   740→          .update(costBaselines)
   741→          .set({
   742→            budgetLaborCost: baseline.budgetLaborCost.toString(),
   743→            budgetMaterialCost: baseline.budgetMaterialCost.toString(),
   744→            budgetTotal: budgetTotal.toString(),
   745→            budgetLaborHours: baseline.budgetLaborHours?.toString() || null,
   746→            updatedAt: new Date(),
   747→          })
   748→          .where(eq(costBaselines.id, existing.id))
   749→          .returning();
   750→
   751→        return updated;
   752→      }
   753→
   754→      const [created] = await this.db
   755→        .insert(costBaselines)
   756→        .values({
   757→          fiscalYear: baseline.fiscalYear,
   758→          depotId: baseline.depotId || null,
   759→          budgetLaborCost: baseline.budgetLaborCost.toString(),
   760→          budgetMaterialCost: baseline.budgetMaterialCost.toString(),
   761→          budgetTotal: budgetTotal.toString(),
   762→          budgetLaborHours: baseline.budgetLaborHours?.toString() || null,
   763→        })
   764→        .returning();
   765→
   766→      return created;
   767→    });
   768→  }
   769→
   770→  /**
   771→   * Get all cost baselines for a fiscal year
   772→   */
   773→  async getCostBaselines(fiscalYear: number): Promise<(typeof costBaselines.$inferSelect)[]> {
   774→    return this.traced('getCostBaselines', async (span) => {
   775→      span.setAttribute('baseline.fiscal_year', fiscalYear);
   776→
   777→      return this.db.query.costBaselines.findMany({
   778→        where: eq(costBaselines.fiscalYear, fiscalYear),
   779→        with: { depot: true },
   780→      });
   781→    });
   782→  }
   783→
   784→  // ===========================================================================
   785→  // Private Helpers
   786→  // ===========================================================================
   787→
   788→  /**
   789→   * Calculate material cost for a PM type
   790→   */
   791→  private async calculateMaterialCost(pmTypeId: string): Promise<number> {
   792→    // Get material requirements for this PM type
   793→    const requirements = await this.db.query.pmMaterialRequirements.findMany({
   794→      where: eq(pmMaterialRequirements.pmTypeId, pmTypeId),
   795→    });
   796→
   797→    let totalCost = 0;
   798→    const today = new Date().toISOString().split('T')[0];
   799→
   800→    for (const req of requirements) {
   801→      // Get current material cost
   802→      const cost = await this.db.query.materialCosts.findFirst({
   803→        where: and(
   804→          eq(materialCosts.partNumber, req.partNumber),
   805→          lte(materialCosts.effectiveFrom, today),
   806→          sql`(${materialCosts.effectiveTo} IS NULL OR ${materialCosts.effectiveTo} >= ${today})`
   807→        ),
   808→        orderBy: [desc(materialCosts.effectiveFrom)],
   809→      });
   810→
   811→      if (cost) {
   812→        const unitCost = parseFloat(cost.unitCost || '0');
   813→        const quantity = req.quantityPerPm || 1;
   814→        totalCost += unitCost * quantity;
   815→      } else {
   816→        this.log.debug({ partNumber: req.partNumber }, 'No material cost found for part');
   817→      }
   818→    }
   819→
   820→    return totalCost;
   821→  }
   822→
   823→  /**
   824→   * Resolve hours for PM cost calculation
   825→   * Priority: actual > assigned > estimated
   826→   */
   827→  private resolveHours(pm: PmScheduleRecord, pmType: PmTypeRecord | null): number {
   828→    if (pm.actualHours) {
   829→      return parseFloat(pm.actualHours);
   830→    }
   831→    if (pm.assignedHours) {
   832→      return parseFloat(pm.assignedHours);
   833→    }
   834→    if (pmType?.estimatedHours) {
   835→      return parseFloat(pmType.estimatedHours);
   836→    }
   837→    return 0;
   838→  }
   839→
   840→  /**
   841→   * Calculate overtime cost based on shift type
   842→   */
   843→  private calculateOvertimeCost(
   844→    hours: number,
   845→    regularRate: number,
   846→    shift: string,
   847→    rate: LaborRate
   848→  ): number {
   849→    let multiplier = 1;
   850→
   851→    switch (shift) {
   852→      case 'NIGHT':
   853→        multiplier = rate.overtimeMultiplier || DEFAULT_OVERTIME_MULTIPLIER;
   854→        break;
   855→      case 'WEEKEND':
   856→        multiplier = rate.weekendMultiplier || DEFAULT_WEEKEND_MULTIPLIER;
   857→        break;
   858→      case 'HOLIDAY':
   859→        multiplier = rate.holidayMultiplier || 2.5;
   860→        break;
   861→      default:
   862→        return 0; // No overtime for regular shifts
   863→    }
   864→
   865→    // Overtime cost is the premium above regular rate
   866→    return hours * regularRate * (multiplier - 1);
   867→  }
   868→
   869→  /**
   870→   * Map database labor rate to LaborRate type
   871→   */
   872→  private mapLaborRate(rate: typeof laborRates.$inferSelect): LaborRate {
   873→    return {
   874→      id: rate.id,
   875→      depotId: rate.depotId,
   876→      regularHourlyRate: parseFloat(rate.regularHourlyRate || '0'),
   877→      overtimeMultiplier: parseFloat(rate.overtimeMultiplier || '1.5'),
   878→      weekendMultiplier: parseFloat(rate.weekendMultiplier || '2.0'),
   879→      holidayMultiplier: parseFloat(rate.holidayMultiplier || '2.5'),
   880→      shopRateHourly: parseFloat(rate.shopRateHourly || '0'),
   881→      currency: rate.currency || 'SGD',
   882→      effectiveFrom: new Date(rate.effectiveFrom),
   883→      effectiveTo: rate.effectiveTo ? new Date(rate.effectiveTo) : null,
   884→    };
   885→  }
   886→}
