     1→/**
     2→ * MMS Simulation Service (Simulation Engine)
     3→ *
     4→ * Enables what-if scenario analysis with persistent storage and comparison capabilities.
     5→ * Uses event-sourcing pattern for tracking changes through deltas.
     6→ *
     7→ * Key responsibilities:
     8→ * - Create scenarios forked from baselines or other scenarios
     9→ * - Apply changes (PM_MOVE, PM_ADD, PM_REMOVE) as deltas
    10→ * - Materialize scenarios by recursively applying deltas
    11→ * - Compare scenarios side-by-side
    12→ * - Promote winning scenarios to new baselines
    13→ *
    14→ * Scenario lifecycle:
    15→ * ACTIVE -> (changes) -> PROMOTED or EXPIRED
    16→ *
    17→ * Auto-expiration: Scenarios expire after 30 days of inactivity.
    18→ *
    19→ * @see specs/004-domain-services.md Section 4.9
    20→ */
    21→
    22→import { eq, and, desc, asc, sql, inArray, lte, isNull, count, or } from 'drizzle-orm';
    23→import { addDays, format, parseISO, differenceInDays } from 'date-fns';
    24→import { BaseService } from '../lib/services/base';
    25→import {
    26→  scenarios,
    27→  scenarioDeltas,
    28→  scenarioComparisons,
    29→  planBaselines,
    30→  baselinePmSchedule,
    31→  pmSchedule,
    32→  auditLog,
    33→  type Scenario,
    34→  type ScenarioDelta,
    35→  type PlanBaseline,
    36→} from '../lib/db/schema';
    37→import {
    38→  NotFoundError,
    39→  ValidationError,
    40→  BusinessRuleError,
    41→} from '../lib/errors';
    42→
    43→// =============================================================================
    44→// Types
    45→// =============================================================================
    46→
    47→/** Status of a scenario in its lifecycle */
    48→export type ScenarioStatus = 'ACTIVE' | 'PROMOTED' | 'DISCARDED' | 'EXPIRED';
    49→
    50→/** Delta types for scenario changes */
    51→export type DeltaType =
    52→  | 'PM_MOVE'
    53→  | 'PM_ADD'
    54→  | 'PM_REMOVE'
    55→  | 'CAPACITY_CHANGE'
    56→  | 'TRAIN_STATUS_CHANGE';
    57→
    58→/** Entity types that can be modified in scenarios */
    59→export type EntityType = 'pm_schedule' | 'manhour_capacity' | 'train';
    60→
    61→/** Fork source specification */
    62→export interface ForkSource {
    63→  type: 'BASELINE' | 'SCENARIO' | 'PRODUCTION';
    64→  id?: string; // Required for BASELINE and SCENARIO, not for PRODUCTION
    65→}
    66→
    67→/** Request to create a new scenario */
    68→export interface CreateScenarioRequest {
    69→  name: string;
    70→  description?: string;
    71→  forkFrom: ForkSource;
    72→  userId: string;
    73→  expirationDays?: number; // Default: 30
    74→}
    75→
    76→/** Change to apply to a scenario */
    77→export interface ScenarioChange {
    78→  type: DeltaType;
    79→  entityType: EntityType;
    80→  entityId: string;
    81→  oldValues?: Record<string, unknown>;
    82→  newValues?: Record<string, unknown>;
    83→  reason?: string;
    84→}
    85→
    86→/** Materialized PM record with scenario context */
    87→export interface MaterializedPmRecord {
    88→  id: string;
    89→  trainId: string;
    90→  pmTypeId: string;
    91→  targetDate: string;
    92→  assignedTrackId?: string | null;
    93→  assignedHours?: number | null;
    94→  status?: string | null;
    95→  constraintStart?: string | null;
    96→  constraintEnd?: string | null;
    97→  isLocked?: boolean;
    98→  // Additional fields for display
    99→  trainNumber?: string;
   100→  pmCode?: string;
   101→}
   102→
   103→/** Result of scenario materialization */
   104→export interface MaterializedScenario {
   105→  scenario: Scenario | null;
   106→  pmSchedule: MaterializedPmRecord[];
   107→  deltasApplied: number;
   108→  baselineId?: string;
   109→  baselineVersion?: string;
   110→}
   111→
   112→/** PM difference in comparison */
   113→export interface PMDifference {
   114→  pmId: string;
   115→  trainId?: string;
   116→  trainNumber?: string;
   117→  pmTypeId?: string;
   118→  pmCode?: string;
   119→  changeType: 'ADDED' | 'REMOVED' | 'MOVED' | 'UNCHANGED';
   120→  scenarioADate?: string;
   121→  scenarioBDate?: string;
   122→  daysDifference?: number;
   123→}
   124→
   125→/** Aggregated PM differences */
   126→export interface PMDifferenceSummary {
   127→  countDelta: number;
   128→  added: number;
   129→  removed: number;
   130→  moved: number;
   131→  unchanged: number;
   132→  details: PMDifference[];
   133→}
   134→
   135→/** Man-hour difference in comparison */
   136→export interface ManhourDifferenceSummary {
   137→  totalDelta: number;
   138→  overloadedWeeksDelta: number;
   139→  scenarioATotalHours: number;
   140→  scenarioBTotalHours: number;
   141→  details: Array<{
   142→    weekStart: string;
   143→    depotId: string;
   144→    scenarioAHours: number;
   145→    scenarioBHours: number;
   146→    difference: number;
   147→  }>;
   148→}
   149→
   150→/** Cost difference in comparison */
   151→export interface CostDifferenceSummary {
   152→  totalDelta: number;
   153→  laborDelta: number;
   154→  materialDelta: number;
   155→  scenarioATotalCost: number;
   156→  scenarioBTotalCost: number;
   157→}
   158→
   159→/** Full scenario comparison result */
   160→export interface ScenarioComparisonResult {
   161→  comparisonId: string;
   162→  scenarioAId: string;
   163→  scenarioAName?: string;
   164→  scenarioBId?: string;
   165→  scenarioBName?: string;
   166→  baselineId?: string;
   167→  baselineVersion?: string;
   168→  comparisonDate: string;
   169→  pmDifferences: PMDifferenceSummary;
   170→  manhourDifferences: ManhourDifferenceSummary;
   171→  costDifferences: CostDifferenceSummary;
   172→}
   173→
   174→/** Filters for listing scenarios */
   175→export interface ScenarioListFilters {
   176→  status?: ScenarioStatus | ScenarioStatus[];
   177→  createdBy?: string;
   178→  forkedFromBaselineId?: string;
   179→  forkedFromScenarioId?: string;
   180→  searchName?: string;
   181→  includeExpired?: boolean;
   182→}
   183→
   184→/** Pagination options */
   185→export interface ScenarioPaginationOptions {
   186→  page?: number;
   187→  pageSize?: number;
   188→  sortBy?: 'name' | 'createdAt' | 'lastModifiedAt' | 'expiresAt';
   189→  sortOrder?: 'asc' | 'desc';
   190→}
   191→
   192→/** Paginated result for scenarios */
   193→export interface PaginatedScenarioResult {
   194→  data: ScenarioWithMeta[];
   195→  total: number;
   196→  page: number;
   197→  pageSize: number;
   198→  totalPages: number;
   199→}
   200→
   201→/** Scenario with additional metadata */
   202→export interface ScenarioWithMeta extends Scenario {
   203→  deltaCount?: number;
   204→  forkedFromBaselineName?: string;
   205→  forkedFromScenarioName?: string;
   206→  createdByEmail?: string;
   207→}
   208→
   209→/** Request to promote a scenario to baseline */
   210→export interface PromoteScenarioRequest {
   211→  scenarioId: string;
   212→  baselineName: string;
   213→  baselineDescription?: string;
   214→  userId: string;
   215→}
   216→
   217→// =============================================================================
   218→// Singleton instance
   219→// =============================================================================
   220→
   221→let instance: SimulationService | null = null;
   222→
   223→/**
   224→ * Get the singleton SimulationService instance
   225→ */
   226→export function getSimulationService(): SimulationService {
   227→  if (!instance) {
   228→    instance = new SimulationService();
   229→  }
   230→  return instance;
   231→}
   232→
   233→// =============================================================================
   234→// SimulationService Implementation
   235→// =============================================================================
   236→
   237→/**
   238→ * Simulation Service for what-if scenario analysis
   239→ *
   240→ * @example
   241→ * ```typescript
   242→ * const simulationService = getSimulationService();
   243→ *
   244→ * // Create a scenario from published baseline
   245→ * const scenario = await simulationService.createScenario({
   246→ *   name: 'Q2 PM Deferral Analysis',
   247→ *   description: 'What if we defer Q2 overhauls?',
   248→ *   forkFrom: { type: 'BASELINE', id: 'baseline-123' },
   249→ *   userId: 'user-456'
   250→ * });
   251→ *
   252→ * // Apply a change
   253→ * await simulationService.applyChange(scenario.id, {
   254→ *   type: 'PM_MOVE',
   255→ *   entityType: 'pm_schedule',
   256→ *   entityId: 'pm-789',
   257→ *   oldValues: { targetDate: '2026-03-15' },
   258→ *   newValues: { targetDate: '2026-04-15' },
   259→ *   reason: 'Defer to Q2 for resource leveling'
   260→ * }, 'user-456');
   261→ *
   262→ * // Compare with baseline
   263→ * const comparison = await simulationService.compareScenarios(scenario.id, null);
   264→ * console.log(`PM count delta: ${comparison.pmDifferences.countDelta}`);
   265→ *
   266→ * // Promote if approved
   267→ * const baseline = await simulationService.promoteToBaseline({
   268→ *   scenarioId: scenario.id,
   269→ *   baselineName: 'Q2 2026 Optimized Plan',
   270→ *   userId: 'user-456'
   271→ * });
   272→ * ```
   273→ */
   274→export class SimulationService extends BaseService {
   275→  /** Default expiration days for scenarios */
   276→  private readonly defaultExpirationDays = 30;
   277→
   278→  constructor() {
   279→    super({ name: 'simulation-service' });
   280→  }
   281→
   282→  // ===========================================================================
   283→  // Scenario CRUD Operations
   284→  // ===========================================================================
   285→
   286→  /**
   287→   * Create a new scenario forked from baseline, another scenario, or production
   288→   */
   289→  async createScenario(request: CreateScenarioRequest): Promise<Scenario> {
   290→    return this.traced('createScenario', async (span) => {
   291→      span.setAttribute('scenario.name', request.name);
   292→      span.setAttribute('scenario.forkType', request.forkFrom.type);
   293→      if (request.forkFrom.id) {
   294→        span.setAttribute('scenario.forkId', request.forkFrom.id);
   295→      }
   296→
   297→      // Validate fork source
   298→      await this.validateForkSource(request.forkFrom);
   299→
   300→      const expirationDays = request.expirationDays ?? this.defaultExpirationDays;
   301→      const expiresAt = addDays(new Date(), expirationDays);
   302→
   303→      const [scenario] = await this.db
   304→        .insert(scenarios)
   305→        .values({
   306→          name: request.name,
   307→          description: request.description ?? null,
   308→          forkedFromBaselineId:
   309→            request.forkFrom.type === 'BASELINE' ? request.forkFrom.id : null,
   310→          forkedFromScenarioId:
   311→            request.forkFrom.type === 'SCENARIO' ? request.forkFrom.id : null,
   312→          forkedAt: new Date(),
   313→          status: 'ACTIVE',
   314→          createdBy: request.userId,
   315→          createdAt: new Date(),
   316→          lastModifiedAt: new Date(),
   317→          expiresAt,
   318→        })
   319→        .returning();
   320→
   321→      // Audit log
   322→      await this.db.insert(auditLog).values({
   323→        entityType: 'scenario',
   324→        entityId: scenario.id,
   325→        action: 'CREATE',
   326→        userId: request.userId,
   327→        newValues: {
   328→          name: request.name,
   329→          forkFrom: request.forkFrom,
   330→        },
   331→      });
   332→
   333→      this.log.info(
   334→        { scenarioId: scenario.id, name: request.name, forkFrom: request.forkFrom },
   335→        'Created new scenario'
   336→      );
   337→
   338→      return scenario;
   339→    });
   340→  }
   341→
   342→  /**
   343→   * Get a scenario by ID
   344→   */
   345→  async getScenario(scenarioId: string): Promise<ScenarioWithMeta> {
   346→    return this.traced('getScenario', async (span) => {
   347→      span.setAttribute('scenario.id', scenarioId);
   348→
   349→      const scenario = await this.db.query.scenarios.findFirst({
   350→        where: eq(scenarios.id, scenarioId),
   351→        with: {
   352→          forkedFromBaseline: true,
   353→          forkedFromScenario: true,
   354→          createdByUser: true,
   355→          deltas: true,
   356→        },
   357→      });
   358→
   359→      if (!scenario) {
   360→        throw new NotFoundError(`Scenario not found: ${scenarioId}`);
   361→      }
   362→
   363→      return {
   364→        ...scenario,
   365→        deltaCount: scenario.deltas?.length ?? 0,
   366→        forkedFromBaselineName: (scenario.forkedFromBaseline as PlanBaseline | null)?.name,
   367→        forkedFromScenarioName: (scenario.forkedFromScenario as Scenario | null)?.name,
   368→        createdByEmail: (scenario.createdByUser as { email?: string } | null)?.email,
   369→      };
   370→    });
   371→  }
   372→
   373→  /**
   374→   * List scenarios with filtering and pagination
   375→   */
   376→  async listScenarios(
   377→    filters?: ScenarioListFilters,
   378→    pagination?: ScenarioPaginationOptions
   379→  ): Promise<PaginatedScenarioResult> {
   380→    return this.traced('listScenarios', async (span) => {
   381→      const page = pagination?.page ?? 1;
   382→      const pageSize = Math.min(pagination?.pageSize ?? 20, 100);
   383→      const offset = (page - 1) * pageSize;
   384→
   385→      // Build where conditions
   386→      const conditions: ReturnType<typeof eq>[] = [];
   387→
   388→      if (filters?.status) {
   389→        const statuses = Array.isArray(filters.status) ? filters.status : [filters.status];
   390→        conditions.push(inArray(scenarios.status, statuses));
   391→      } else if (!filters?.includeExpired) {
   392→        // By default, exclude expired scenarios
   393→        conditions.push(
   394→          or(
   395→            eq(scenarios.status, 'ACTIVE'),
   396→            eq(scenarios.status, 'PROMOTED')
   397→          )!
   398→        );
   399→      }
   400→
   401→      if (filters?.createdBy) {
   402→        conditions.push(eq(scenarios.createdBy, filters.createdBy));
   403→      }
   404→
   405→      if (filters?.forkedFromBaselineId) {
   406→        conditions.push(eq(scenarios.forkedFromBaselineId, filters.forkedFromBaselineId));
   407→      }
   408→
   409→      if (filters?.forkedFromScenarioId) {
   410→        conditions.push(eq(scenarios.forkedFromScenarioId, filters.forkedFromScenarioId));
   411→      }
   412→
   413→      const whereClause = conditions.length > 0 ? and(...conditions) : undefined;
   414→
   415→      // Get total count
   416→      const [{ total }] = await this.db
   417→        .select({ total: count() })
   418→        .from(scenarios)
   419→        .where(whereClause);
   420→
   421→      // Get scenarios with sorting
   422→      const sortField = pagination?.sortBy ?? 'lastModifiedAt';
   423→      const sortOrder = pagination?.sortOrder ?? 'desc';
   424→
   425→      const orderByClause = sortOrder === 'desc' ? desc(scenarios[sortField]) : asc(scenarios[sortField]);
   426→
   427→      const data = await this.db.query.scenarios.findMany({
   428→        where: whereClause,
   429→        orderBy: orderByClause,
   430→        limit: pageSize,
   431→        offset,
   432→        with: {
   433→          forkedFromBaseline: true,
   434→          forkedFromScenario: true,
   435→          deltas: true,
   436→        },
   437→      });
   438→
   439→      const scenariosWithMeta: ScenarioWithMeta[] = data.map((s) => ({
   440→        ...s,
   441→        deltaCount: s.deltas?.length ?? 0,
   442→        forkedFromBaselineName: (s.forkedFromBaseline as PlanBaseline | null)?.name,
   443→        forkedFromScenarioName: (s.forkedFromScenario as Scenario | null)?.name,
   444→      }));
   445→
   446→      span.setAttribute('scenario.count', scenariosWithMeta.length);
   447→      span.setAttribute('scenario.total', total);
   448→
   449→      return {
   450→        data: scenariosWithMeta,
   451→        total,
   452→        page,
   453→        pageSize,
   454→        totalPages: Math.ceil(total / pageSize),
   455→      };
   456→    });
   457→  }
