/**
 * MMS Simulation Service (Simulation Engine)
 *
 * Enables what-if scenario analysis with persistent storage and comparison capabilities.
 * Uses event-sourcing pattern for tracking changes through deltas.
 *
 * Key responsibilities:
 * - Create scenarios forked from baselines or other scenarios
 * - Apply changes (PM_MOVE, PM_ADD, PM_REMOVE) as deltas
 * - Materialize scenarios by recursively applying deltas
 * - Compare scenarios side-by-side
 * - Promote winning scenarios to new baselines
 *
 * Scenario lifecycle:
 * ACTIVE -> (changes) -> PROMOTED or EXPIRED
 *
 * Auto-expiration: Scenarios expire after 30 days of inactivity.
 *
 * @see specs/004-domain-services.md Section 4.9
 */

import { eq, and, desc, asc, sql, inArray, lte, isNull, count, or } from 'drizzle-orm';
import { addDays, format, parseISO, differenceInDays } from 'date-fns';
import { BaseService } from '../lib/services/base';
import {
  scenarios,
  scenarioDeltas,
  scenarioComparisons,
  planBaselines,
  baselinePmSchedule,
  pmSchedule,
  auditLog,
  type Scenario,
  type ScenarioDelta,
  type PlanBaseline,
} from '../lib/db/schema';
import {
  NotFoundError,
  ValidationError,
  BusinessRuleError,
} from '../lib/errors';

// =============================================================================
// Types
// =============================================================================

/** Status of a scenario in its lifecycle */
export type ScenarioStatus = 'ACTIVE' | 'PROMOTED' | 'DISCARDED' | 'EXPIRED';

/** Delta types for scenario changes */
export type DeltaType =
  | 'PM_MOVE'
  | 'PM_ADD'
  | 'PM_REMOVE'
  | 'CAPACITY_CHANGE'
  | 'TRAIN_STATUS_CHANGE';

/** Entity types that can be modified in scenarios */
export type EntityType = 'pm_schedule' | 'manhour_capacity' | 'train';

/** Fork source specification */
export interface ForkSource {
  type: 'BASELINE' | 'SCENARIO' | 'PRODUCTION';
  id?: string; // Required for BASELINE and SCENARIO, not for PRODUCTION
}

/** Request to create a new scenario */
export interface CreateScenarioRequest {
  name: string;
  description?: string;
  forkFrom: ForkSource;
  userId: string;
  expirationDays?: number; // Default: 30
}

/** Change to apply to a scenario */
export interface ScenarioChange {
  type: DeltaType;
  entityType: EntityType;
  entityId: string;
  oldValues?: Record<string, unknown>;
  newValues?: Record<string, unknown>;
  reason?: string;
}

/** Materialized PM record with scenario context */
export interface MaterializedPmRecord {
  id: string;
  trainId: string;
  pmTypeId: string;
  targetDate: string;
  assignedTrackId?: string | null;
  assignedHours?: number | null;
  status?: string | null;
  constraintStart?: string | null;
  constraintEnd?: string | null;
  isLocked?: boolean;
  // Additional fields for display
  trainNumber?: string;
  pmCode?: string;
}

/** Result of scenario materialization */
export interface MaterializedScenario {
  scenario: Scenario | null;
  pmSchedule: MaterializedPmRecord[];
  deltasApplied: number;
  baselineId?: string;
  baselineVersion?: string;
}

/** PM difference in comparison */
export interface PMDifference {
  pmId: string;
  trainId?: string;
  trainNumber?: string;
  pmTypeId?: string;
  pmCode?: string;
  changeType: 'ADDED' | 'REMOVED' | 'MOVED' | 'UNCHANGED';
  scenarioADate?: string;
  scenarioBDate?: string;
  daysDifference?: number;
}

/** Aggregated PM differences */
export interface PMDifferenceSummary {
  countDelta: number;
  added: number;
  removed: number;
  moved: number;
  unchanged: number;
  details: PMDifference[];
}

/** Man-hour difference in comparison */
export interface ManhourDifferenceSummary {
  totalDelta: number;
  overloadedWeeksDelta: number;
  scenarioATotalHours: number;
  scenarioBTotalHours: number;
  details: Array<{
    weekStart: string;
    depotId: string;
    scenarioAHours: number;
    scenarioBHours: number;
    difference: number;
  }>;
}

/** Cost difference in comparison */
export interface CostDifferenceSummary {
  totalDelta: number;
  laborDelta: number;
  materialDelta: number;
  scenarioATotalCost: number;
  scenarioBTotalCost: number;
}

/** Full scenario comparison result */
export interface ScenarioComparisonResult {
  comparisonId: string;
  scenarioAId: string;
  scenarioAName?: string;
  scenarioBId?: string;
  scenarioBName?: string;
  baselineId?: string;
  baselineVersion?: string;
  comparisonDate: string;
  pmDifferences: PMDifferenceSummary;
  manhourDifferences: ManhourDifferenceSummary;
  costDifferences: CostDifferenceSummary;
}

/** Filters for listing scenarios */
export interface ScenarioListFilters {
  status?: ScenarioStatus | ScenarioStatus[];
  createdBy?: string;
  forkedFromBaselineId?: string;
  forkedFromScenarioId?: string;
  searchName?: string;
  includeExpired?: boolean;
}

/** Pagination options */
export interface ScenarioPaginationOptions {
  page?: number;
  pageSize?: number;
  sortBy?: 'name' | 'createdAt' | 'lastModifiedAt' | 'expiresAt';
  sortOrder?: 'asc' | 'desc';
}

/** Paginated result for scenarios */
export interface PaginatedScenarioResult {
  data: ScenarioWithMeta[];
  total: number;
  page: number;
  pageSize: number;
  totalPages: number;
}

/** Scenario with additional metadata */
export interface ScenarioWithMeta extends Scenario {
  deltaCount?: number;
  forkedFromBaselineName?: string;
  forkedFromScenarioName?: string;
  createdByEmail?: string;
}

/** Request to promote a scenario to baseline */
export interface PromoteScenarioRequest {
  scenarioId: string;
  baselineName: string;
  baselineDescription?: string;
  userId: string;
}

// =============================================================================
// Singleton instance
// =============================================================================

let instance: SimulationService | null = null;

/**
 * Get the singleton SimulationService instance
 */
export function getSimulationService(): SimulationService {
  if (!instance) {
    instance = new SimulationService();
  }
  return instance;
}

// =============================================================================
// SimulationService Implementation
// =============================================================================

/**
 * Simulation Service for what-if scenario analysis
 *
 * @example
 * ```typescript
 * const simulationService = getSimulationService();
 *
 * // Create a scenario from published baseline
 * const scenario = await simulationService.createScenario({
 *   name: 'Q2 PM Deferral Analysis',
 *   description: 'What if we defer Q2 overhauls?',
 *   forkFrom: { type: 'BASELINE', id: 'baseline-123' },
 *   userId: 'user-456'
 * });
 *
 * // Apply a change
 * await simulationService.applyChange(scenario.id, {
 *   type: 'PM_MOVE',
 *   entityType: 'pm_schedule',
 *   entityId: 'pm-789',
 *   oldValues: { targetDate: '2026-03-15' },
 *   newValues: { targetDate: '2026-04-15' },
 *   reason: 'Defer to Q2 for resource leveling'
 * }, 'user-456');
 *
 * // Compare with baseline
 * const comparison = await simulationService.compareScenarios(scenario.id, null);
 * console.log(`PM count delta: ${comparison.pmDifferences.countDelta}`);
 *
 * // Promote if approved
 * const baseline = await simulationService.promoteToBaseline({
 *   scenarioId: scenario.id,
 *   baselineName: 'Q2 2026 Optimized Plan',
 *   userId: 'user-456'
 * });
 * ```
 */
export class SimulationService extends BaseService {
  /** Default expiration days for scenarios */
  private readonly defaultExpirationDays = 30;

  constructor() {
    super({ name: 'simulation-service' });
  }

  // ===========================================================================
  // Scenario CRUD Operations
  // ===========================================================================

  /**
   * Create a new scenario forked from baseline, another scenario, or production
   */
  async createScenario(request: CreateScenarioRequest): Promise<Scenario> {
    return this.traced('createScenario', async (span) => {
      span.setAttribute('scenario.name', request.name);
      span.setAttribute('scenario.forkType', request.forkFrom.type);
      if (request.forkFrom.id) {
        span.setAttribute('scenario.forkId', request.forkFrom.id);
      }

      // Validate fork source
      await this.validateForkSource(request.forkFrom);

      const expirationDays = request.expirationDays ?? this.defaultExpirationDays;
      const expiresAt = addDays(new Date(), expirationDays);

      const [scenario] = await this.db
        .insert(scenarios)
        .values({
          name: request.name,
          description: request.description ?? null,
          forkedFromBaselineId:
            request.forkFrom.type === 'BASELINE' ? request.forkFrom.id : null,
          forkedFromScenarioId:
            request.forkFrom.type === 'SCENARIO' ? request.forkFrom.id : null,
          forkedAt: new Date(),
          status: 'ACTIVE',
          createdBy: request.userId,
          createdAt: new Date(),
          lastModifiedAt: new Date(),
          expiresAt,
        })
        .returning();

      // Audit log
      await this.db.insert(auditLog).values({
        entityType: 'scenario',
        entityId: scenario.id,
        action: 'CREATE',
        userId: request.userId,
        newValues: {
          name: request.name,
          forkFrom: request.forkFrom,
        },
      });

      this.log.info(
        { scenarioId: scenario.id, name: request.name, forkFrom: request.forkFrom },
        'Created new scenario'
      );

      return scenario;
    });
  }

  /**
   * Get a scenario by ID
   */
  async getScenario(scenarioId: string): Promise<ScenarioWithMeta> {
    return this.traced('getScenario', async (span) => {
      span.setAttribute('scenario.id', scenarioId);

      const scenario = await this.db.query.scenarios.findFirst({
        where: eq(scenarios.id, scenarioId),
        with: {
          forkedFromBaseline: true,
          forkedFromScenario: true,
          createdByUser: true,
          deltas: true,
        },
      });

      if (!scenario) {
        throw new NotFoundError(`Scenario not found: ${scenarioId}`);
      }

      return {
        ...scenario,
        deltaCount: scenario.deltas?.length ?? 0,
        forkedFromBaselineName: (scenario.forkedFromBaseline as PlanBaseline | null)?.name,
        forkedFromScenarioName: (scenario.forkedFromScenario as Scenario | null)?.name,
        createdByEmail: (scenario.createdByUser as { email?: string } | null)?.email,
      };
    });
  }

  /**
   * List scenarios with filtering and pagination
   */
  async listScenarios(
    filters?: ScenarioListFilters,
    pagination?: ScenarioPaginationOptions
  ): Promise<PaginatedScenarioResult> {
    return this.traced('listScenarios', async (span) => {
      const page = pagination?.page ?? 1;
      const pageSize = Math.min(pagination?.pageSize ?? 20, 100);
      const offset = (page - 1) * pageSize;

      // Build where conditions
      const conditions: ReturnType<typeof eq>[] = [];

      if (filters?.status) {
        const statuses = Array.isArray(filters.status) ? filters.status : [filters.status];
        conditions.push(inArray(scenarios.status, statuses));
      } else if (!filters?.includeExpired) {
        // By default, exclude expired scenarios
        conditions.push(
          or(
            eq(scenarios.status, 'ACTIVE'),
            eq(scenarios.status, 'PROMOTED')
          )!
        );
      }

      if (filters?.createdBy) {
        conditions.push(eq(scenarios.createdBy, filters.createdBy));
      }

      if (filters?.forkedFromBaselineId) {
        conditions.push(eq(scenarios.forkedFromBaselineId, filters.forkedFromBaselineId));
      }

      if (filters?.forkedFromScenarioId) {
        conditions.push(eq(scenarios.forkedFromScenarioId, filters.forkedFromScenarioId));
      }

      const whereClause = conditions.length > 0 ? and(...conditions) : undefined;

      // Get total count
      const [{ total }] = await this.db
        .select({ total: count() })
        .from(scenarios)
        .where(whereClause);

      // Get scenarios with sorting
      const sortField = pagination?.sortBy ?? 'lastModifiedAt';
      const sortOrder = pagination?.sortOrder ?? 'desc';

      const orderByClause = sortOrder === 'desc' ? desc(scenarios[sortField]) : asc(scenarios[sortField]);

      const data = await this.db.query.scenarios.findMany({
        where: whereClause,
        orderBy: orderByClause,
        limit: pageSize,
        offset,
        with: {
          forkedFromBaseline: true,
          forkedFromScenario: true,
          deltas: true,
        },
      });

      const scenariosWithMeta: ScenarioWithMeta[] = data.map((s) => ({
        ...s,
        deltaCount: s.deltas?.length ?? 0,
        forkedFromBaselineName: (s.forkedFromBaseline as PlanBaseline | null)?.name,
        forkedFromScenarioName: (s.forkedFromScenario as Scenario | null)?.name,
      }));

      span.setAttribute('scenario.count', scenariosWithMeta.length);
      span.setAttribute('scenario.total', total);

      return {
        data: scenariosWithMeta,
        total,
        page,
        pageSize,
        totalPages: Math.ceil(total / pageSize),
      };
    });
  }

  /**
   * Delete a scenario (only if ACTIVE and not promoted)
   */
  async deleteScenario(scenarioId: string, userId: string): Promise<void> {
    return this.traced('deleteScenario', async (span) => {
      span.setAttribute('scenario.id', scenarioId);

      const scenario = await this.db.query.scenarios.findFirst({
        where: eq(scenarios.id, scenarioId),
      });

      if (!scenario) {
        throw new NotFoundError(`Scenario not found: ${scenarioId}`);
      }

      if (scenario.status === 'PROMOTED') {
        throw new BusinessRuleError(
          'Cannot delete a promoted scenario',
          { rule: 'SCENARIO_PROMOTED' }
        );
      }

      // Delete scenario (cascades to deltas)
      await this.db.delete(scenarios).where(eq(scenarios.id, scenarioId));

      // Audit log
      await this.db.insert(auditLog).values({
        entityType: 'scenario',
        entityId: scenarioId,
        action: 'DELETE',
        userId,
        oldValues: { name: scenario.name, status: scenario.status },
      });

      this.log.info({ scenarioId, name: scenario.name }, 'Deleted scenario');
    });
  }

  // ===========================================================================
  // Delta Management (Event Sourcing)
  // ===========================================================================

  /**
   * Apply a change to a scenario (event-sourced)
   */
  async applyChange(
    scenarioId: string,
    change: ScenarioChange,
    userId: string
  ): Promise<ScenarioDelta> {
    return this.traced('applyChange', async (span) => {
      span.setAttribute('scenario.id', scenarioId);
      span.setAttribute('delta.type', change.type);
      span.setAttribute('delta.entityType', change.entityType);
      span.setAttribute('delta.entityId', change.entityId);

      // Validate scenario is active
      const scenario = await this.db.query.scenarios.findFirst({
        where: eq(scenarios.id, scenarioId),
      });

      if (!scenario) {
        throw new NotFoundError(`Scenario not found: ${scenarioId}`);
      }

      if (scenario.status !== 'ACTIVE') {
        throw new BusinessRuleError(
          `Cannot apply changes to a ${scenario.status} scenario`,
          { rule: 'SCENARIO_NOT_ACTIVE' }
        );
      }

      // Validate the change
      await this.validateChange(scenarioId, change);

      // Get next sequence number
      const lastDelta = await this.db.query.scenarioDeltas.findFirst({
        where: eq(scenarioDeltas.scenarioId, scenarioId),
        orderBy: desc(scenarioDeltas.sequenceNum),
      });

      const sequenceNum = (lastDelta?.sequenceNum ?? 0) + 1;

      // Record delta
      const [delta] = await this.db
        .insert(scenarioDeltas)
        .values({
          scenarioId,
          sequenceNum,
          deltaType: change.type,
          entityType: change.entityType,
          entityId: change.entityId,
          oldValues: change.oldValues ?? null,
          newValues: change.newValues ?? null,
          changeReason: change.reason ?? null,
          createdBy: userId,
          createdAt: new Date(),
        })
        .returning();

      // Update scenario timestamp and reset expiration
      await this.db
        .update(scenarios)
        .set({
          lastModifiedAt: new Date(),
          expiresAt: addDays(new Date(), this.defaultExpirationDays),
        })
        .where(eq(scenarios.id, scenarioId));

      this.log.info(
        { scenarioId, deltaId: delta.id, deltaType: change.type, sequenceNum },
        'Applied change to scenario'
      );

      return delta;
    });
  }

  /**
   * Get all deltas for a scenario in order
   */
  async getScenarioDeltas(scenarioId: string): Promise<ScenarioDelta[]> {
    return this.traced('getScenarioDeltas', async (span) => {
      span.setAttribute('scenario.id', scenarioId);

      const deltas = await this.db.query.scenarioDeltas.findMany({
        where: eq(scenarioDeltas.scenarioId, scenarioId),
        orderBy: asc(scenarioDeltas.sequenceNum),
      });

      span.setAttribute('delta.count', deltas.length);
      return deltas;
    });
  }

  /**
   * Undo the last delta applied to a scenario
   */
  async undoLastChange(scenarioId: string, userId: string): Promise<void> {
    return this.traced('undoLastChange', async (span) => {
      span.setAttribute('scenario.id', scenarioId);

      const scenario = await this.db.query.scenarios.findFirst({
        where: eq(scenarios.id, scenarioId),
      });

      if (!scenario) {
        throw new NotFoundError(`Scenario not found: ${scenarioId}`);
      }

      if (scenario.status !== 'ACTIVE') {
        throw new BusinessRuleError(
          `Cannot undo changes on a ${scenario.status} scenario`,
          { rule: 'SCENARIO_NOT_ACTIVE' }
        );
      }

      // Get last delta
      const lastDelta = await this.db.query.scenarioDeltas.findFirst({
        where: eq(scenarioDeltas.scenarioId, scenarioId),
        orderBy: desc(scenarioDeltas.sequenceNum),
      });

      if (!lastDelta) {
        throw new BusinessRuleError(
          'No changes to undo',
          { rule: 'NO_CHANGES_TO_UNDO' }
        );
      }

      // Delete the last delta
      await this.db
        .delete(scenarioDeltas)
        .where(eq(scenarioDeltas.id, lastDelta.id));

      // Update scenario timestamp
      await this.db
        .update(scenarios)
        .set({ lastModifiedAt: new Date() })
        .where(eq(scenarios.id, scenarioId));

      // Audit log
      await this.db.insert(auditLog).values({
        entityType: 'scenario_delta',
        entityId: lastDelta.id,
        action: 'DELETE',
        userId,
        oldValues: {
          deltaType: lastDelta.deltaType,
          entityId: lastDelta.entityId,
          sequenceNum: lastDelta.sequenceNum,
          undoOperation: true,
        },
      });

      this.log.info(
        { scenarioId, deltaId: lastDelta.id, deltaType: lastDelta.deltaType },
        'Undid last change'
      );
    });
  }

  // ===========================================================================
  // Scenario Materialization
  // ===========================================================================

  /**
   * Materialize a scenario (apply all deltas to get full state)
   */
  async materializeScenario(scenarioId: string): Promise<MaterializedScenario> {
    return this.traced('materializeScenario', async (span) => {
      span.setAttribute('scenario.id', scenarioId);

      const scenario = await this.db.query.scenarios.findFirst({
        where: eq(scenarios.id, scenarioId),
        with: {
          forkedFromBaseline: true,
        },
      });

      if (!scenario) {
        throw new NotFoundError(`Scenario not found: ${scenarioId}`);
      }

      // Get base state
      let basePMSchedule: MaterializedPmRecord[];
      let baselineId: string | undefined;
      let baselineVersion: string | undefined;

      if (scenario.forkedFromBaselineId) {
        // Fork from baseline
        baselineId = scenario.forkedFromBaselineId;
        baselineVersion = (scenario.forkedFromBaseline as PlanBaseline | null)?.version ?? undefined;

        const baselineRecords = await this.db.query.baselinePmSchedule.findMany({
          where: eq(baselinePmSchedule.baselineId, scenario.forkedFromBaselineId),
        });

        basePMSchedule = baselineRecords.map((r) => ({
          id: r.id,
          trainId: r.trainId,
          pmTypeId: r.pmTypeId,
          targetDate: r.projectedDate,
          assignedTrackId: null,
          assignedHours: null,
          status: 'SCHEDULED',
        }));
      } else if (scenario.forkedFromScenarioId) {
        // Recursive materialization from parent scenario
        const parentScenario = await this.materializeScenario(scenario.forkedFromScenarioId);
        basePMSchedule = parentScenario.pmSchedule;
        baselineId = parentScenario.baselineId;
        baselineVersion = parentScenario.baselineVersion;
      } else {
        // Fork from current production
        const productionRecords = await this.db.query.pmSchedule.findMany({
          where: isNull(pmSchedule.scenarioId),
        });

        basePMSchedule = productionRecords.map((r) => ({
          id: r.id,
          trainId: r.trainId,
          pmTypeId: r.pmTypeId,
          targetDate: r.targetDate,
          assignedTrackId: r.assignedTrackId,
          assignedHours: r.assignedHours ? Number(r.assignedHours) : null,
          status: r.status,
          constraintStart: r.constraintStart,
          constraintEnd: r.constraintEnd,
          isLocked: r.isLocked ?? false,
        }));
      }

      // Get all deltas in order
      const deltas = await this.db.query.scenarioDeltas.findMany({
        where: eq(scenarioDeltas.scenarioId, scenarioId),
        orderBy: asc(scenarioDeltas.sequenceNum),
      });

      // Apply deltas
      const materializedPMSchedule = [...basePMSchedule];

      for (const delta of deltas) {
        if (delta.entityType !== 'pm_schedule') continue;

        switch (delta.deltaType) {
          case 'PM_MOVE': {
            const idx = materializedPMSchedule.findIndex((pm) => pm.id === delta.entityId);
            if (idx >= 0 && delta.newValues) {
              const newValues = delta.newValues as Record<string, unknown>;
              materializedPMSchedule[idx] = {
                ...materializedPMSchedule[idx],
                targetDate: newValues.targetDate as string ?? materializedPMSchedule[idx].targetDate,
                assignedTrackId: newValues.assignedTrackId as string ?? materializedPMSchedule[idx].assignedTrackId,
                assignedHours: newValues.assignedHours as number ?? materializedPMSchedule[idx].assignedHours,
              };
            }
            break;
          }
          case 'PM_ADD': {
            if (delta.newValues) {
              const newValues = delta.newValues as Record<string, unknown>;
              materializedPMSchedule.push({
                id: delta.entityId,
                trainId: newValues.trainId as string,
                pmTypeId: newValues.pmTypeId as string,
                targetDate: newValues.targetDate as string,
                assignedTrackId: newValues.assignedTrackId as string | null ?? null,
                assignedHours: newValues.assignedHours as number | null ?? null,
                status: 'SCHEDULED',
              });
            }
            break;
          }
          case 'PM_REMOVE': {
            const idx = materializedPMSchedule.findIndex((pm) => pm.id === delta.entityId);
            if (idx >= 0) {
              materializedPMSchedule.splice(idx, 1);
            }
            break;
          }
        }
      }

      span.setAttribute('materialized.pmCount', materializedPMSchedule.length);
      span.setAttribute('materialized.deltasApplied', deltas.length);

      return {
        scenario,
        pmSchedule: materializedPMSchedule,
        deltasApplied: deltas.length,
        baselineId,
        baselineVersion,
      };
    });
  }

  // ===========================================================================
  // Scenario Comparison
  // ===========================================================================

  /**
   * Compare two scenarios or scenario vs baseline
   */
  async compareScenarios(
    scenarioAId: string,
    scenarioBId: string | null,
    baselineId?: string
  ): Promise<ScenarioComparisonResult> {
    return this.traced('compareScenarios', async (span) => {
      span.setAttribute('comparison.scenarioAId', scenarioAId);
      if (scenarioBId) span.setAttribute('comparison.scenarioBId', scenarioBId);
      if (baselineId) span.setAttribute('comparison.baselineId', baselineId);

      // Materialize scenario A
      const scenarioA = await this.materializeScenario(scenarioAId);

      // Get scenario B (another scenario or baseline)
      let scenarioB: MaterializedScenario;
      let scenarioBName: string | undefined;

      if (scenarioBId) {
        scenarioB = await this.materializeScenario(scenarioBId);
        scenarioBName = scenarioB.scenario?.name;
      } else {
        // Use baseline
        const baseline = baselineId
          ? await this.db.query.planBaselines.findFirst({
              where: eq(planBaselines.id, baselineId),
            })
          : await this.getPublishedBaseline();

        if (!baseline) {
          throw new NotFoundError('No baseline for comparison');
        }

        const baselinePMs = await this.db.query.baselinePmSchedule.findMany({
          where: eq(baselinePmSchedule.baselineId, baseline.id),
        });

        scenarioB = {
          scenario: null,
          pmSchedule: baselinePMs.map((r) => ({
            id: r.id,
            trainId: r.trainId,
            pmTypeId: r.pmTypeId,
            targetDate: r.projectedDate,
            assignedTrackId: null,
            assignedHours: null,
            status: 'SCHEDULED',
          })),
          deltasApplied: 0,
          baselineId: baseline.id,
          baselineVersion: baseline.version ?? undefined,
        };
        scenarioBName = `Baseline: ${baseline.name}`;
      }

      // Calculate differences
      const pmDifferences = this.calculatePMDifferences(
        scenarioA.pmSchedule,
        scenarioB.pmSchedule
      );

      const manhourDifferences = await this.calculateManhourDifferences(
        scenarioA.pmSchedule,
        scenarioB.pmSchedule
      );

      const costDifferences = await this.calculateCostDifferences(
        scenarioA.pmSchedule,
        scenarioB.pmSchedule
      );

      // Persist comparison
      const comparisonDate = format(new Date(), 'yyyy-MM-dd');
      const [comparison] = await this.db
        .insert(scenarioComparisons)
        .values({
          scenarioAId,
          scenarioBId,
          baselineId: scenarioBId ? null : (baselineId ?? scenarioB.baselineId),
          comparisonDate,
          pmCountDelta: pmDifferences.countDelta,
          totalHoursDelta: String(manhourDifferences.totalDelta),
          totalCostDelta: String(costDifferences.totalDelta),
          overloadedWeeksDelta: manhourDifferences.overloadedWeeksDelta,
          pmDifferences: pmDifferences.details,
          manhourDifferences: manhourDifferences.details,
        })
        .returning();

      span.setAttribute('comparison.pmCountDelta', pmDifferences.countDelta);
      span.setAttribute('comparison.totalHoursDelta', manhourDifferences.totalDelta);

      return {
        comparisonId: comparison.id,
        scenarioAId,
        scenarioAName: scenarioA.scenario?.name,
        scenarioBId: scenarioBId ?? undefined,
        scenarioBName,
        baselineId: scenarioB.baselineId,
        baselineVersion: scenarioB.baselineVersion,
        comparisonDate,
        pmDifferences,
        manhourDifferences,
        costDifferences,
      };
    });
  }

  // ===========================================================================
  // Scenario Promotion
  // ===========================================================================

  /**
   * Promote a scenario to become the new baseline
   */
  async promoteToBaseline(request: PromoteScenarioRequest): Promise<PlanBaseline> {
    return this.inTransaction('promoteToBaseline', async (tx, span) => {
      span.setAttribute('scenario.id', request.scenarioId);
      span.setAttribute('baseline.name', request.baselineName);

      // Verify scenario exists and is active
      const scenario = await tx.query.scenarios.findFirst({
        where: eq(scenarios.id, request.scenarioId),
      });

      if (!scenario) {
        throw new NotFoundError(`Scenario not found: ${request.scenarioId}`);
      }

      if (scenario.status !== 'ACTIVE') {
        throw new BusinessRuleError(
          `Cannot promote a ${scenario.status} scenario`,
          { rule: 'SCENARIO_NOT_ACTIVE' }
        );
      }

      // Materialize the scenario
      const materialized = await this.materializeScenario(request.scenarioId);

      // Get next version
      const latestBaseline = await tx.query.planBaselines.findFirst({
        orderBy: desc(planBaselines.version),
      });

      const version = this.incrementVersion(latestBaseline?.version);

      // Create new baseline
      const [baseline] = await tx
        .insert(planBaselines)
        .values({
          name: request.baselineName,
          version,
          baselineDate: format(new Date(), 'yyyy-MM-dd'),
          status: 'PUBLISHED',
          description: request.baselineDescription ?? `Promoted from scenario: ${scenario.name}`,
          createdBy: request.userId,
          publishedBy: request.userId,
          publishedAt: new Date(),
          horizonEnd: format(addDays(new Date(), 365 * 10), 'yyyy-MM-dd'), // 10-year horizon
          fleetCount: null, // Will be calculated
          totalPmScheduled: materialized.pmSchedule.length,
          totalManhourProjected: null,
        })
        .returning();

      // Copy materialized PM schedule to baseline snapshots
      if (materialized.pmSchedule.length > 0) {
        await tx.insert(baselinePmSchedule).values(
          materialized.pmSchedule.map((pm) => ({
            baselineId: baseline.id,
            trainId: pm.trainId,
            pmTypeId: pm.pmTypeId,
            projectedDate: pm.targetDate,
          }))
        );
      }

      // Apply scenario deltas to production PM schedule
      const deltas = await this.getScenarioDeltas(request.scenarioId);
      for (const delta of deltas) {
        if (delta.entityType !== 'pm_schedule') continue;

        switch (delta.deltaType) {
          case 'PM_MOVE': {
            if (delta.newValues) {
              const newValues = delta.newValues as Record<string, unknown>;
              await tx
                .update(pmSchedule)
                .set({
                  targetDate: newValues.targetDate as string,
                  assignedTrackId: newValues.assignedTrackId as string | undefined,
                  assignedHours: newValues.assignedHours as string | undefined,
                  updatedAt: new Date(),
                })
                .where(eq(pmSchedule.id, delta.entityId));
            }
            break;
          }
          case 'PM_ADD': {
            if (delta.newValues) {
              const newValues = delta.newValues as Record<string, unknown>;
              // Use target date +/- 14 days as default compliance window if not specified
              const targetDateStr = newValues.targetDate as string;
              const targetDateObj = parseISO(targetDateStr);
              const constraintStart = (newValues.constraintStart as string) ??
                format(addDays(targetDateObj, -14), 'yyyy-MM-dd');
              const constraintEnd = (newValues.constraintEnd as string) ??
                format(addDays(targetDateObj, 14), 'yyyy-MM-dd');

              await tx.insert(pmSchedule).values({
                trainId: newValues.trainId as string,
                pmTypeId: newValues.pmTypeId as string,
                targetDate: targetDateStr,
                constraintStart,
                constraintEnd,
                status: 'SCHEDULED',
                scenarioId: null, // Production
              });
            }
            break;
          }
          case 'PM_REMOVE': {
            await tx
              .update(pmSchedule)
              .set({ status: 'CANCELLED', updatedAt: new Date() })
              .where(eq(pmSchedule.id, delta.entityId));
            break;
          }
        }
      }

      // Mark scenario as promoted
      await tx
        .update(scenarios)
        .set({
          status: 'PROMOTED',
          promotedToBaselineId: baseline.id,
          promotedAt: new Date(),
          promotedBy: request.userId,
        })
        .where(eq(scenarios.id, request.scenarioId));

      // Supersede previous published baseline
      await tx
        .update(planBaselines)
        .set({ status: 'SUPERSEDED' })
        .where(
          and(
            eq(planBaselines.status, 'PUBLISHED'),
            sql`${planBaselines.id} != ${baseline.id}`
          )
        );

      // Audit log
      await tx.insert(auditLog).values({
        entityType: 'baseline',
        entityId: baseline.id,
        action: 'CREATE',
        userId: request.userId,
        newValues: {
          name: baseline.name,
          version: baseline.version,
          promotedFromScenario: request.scenarioId,
        },
      });

      this.log.info(
        {
          scenarioId: request.scenarioId,
          baselineId: baseline.id,
          version: baseline.version,
        },
        'Promoted scenario to baseline'
      );

      return baseline;
    });
  }

