  // Utility Functions
  // ===========================================================================

  /**
   * Get the current published baseline
   */
  async getPublishedBaseline(): Promise<PlanBaseline | null> {
    const baseline = await this.db.query.planBaselines.findFirst({
      where: eq(planBaselines.status, 'PUBLISHED'),
      orderBy: desc(planBaselines.publishedAt),
    });
    return baseline ?? null;
  }

  /**
   * Cleanup expired scenarios
   */
  async cleanupExpiredScenarios(): Promise<number> {
    return this.traced('cleanupExpiredScenarios', async (span) => {
      const now = new Date();

      const result = await this.db
        .update(scenarios)
        .set({ status: 'EXPIRED' })
        .where(
          and(
            eq(scenarios.status, 'ACTIVE'),
            lte(scenarios.expiresAt, now)
          )
        )
        .returning({ id: scenarios.id });

      span.setAttribute('expired.count', result.length);
      this.log.info({ expiredCount: result.length }, 'Cleaned up expired scenarios');

      return result.length;
    });
  }

  // ===========================================================================
  // Private Helper Methods
  // ===========================================================================

  /**
   * Validate that the fork source exists
   */
  private async validateForkSource(forkFrom: ForkSource): Promise<void> {
    if (forkFrom.type === 'PRODUCTION') {
      // No validation needed for production fork
      return;
    }

    if (!forkFrom.id) {
      throw new ValidationError(`Fork ID required for type ${forkFrom.type}`);
    }

    if (forkFrom.type === 'BASELINE') {
      const baseline = await this.db.query.planBaselines.findFirst({
        where: eq(planBaselines.id, forkFrom.id),
      });
      if (!baseline) {
        throw new NotFoundError(`Baseline not found: ${forkFrom.id}`);
      }
    } else if (forkFrom.type === 'SCENARIO') {
      const scenario = await this.db.query.scenarios.findFirst({
        where: eq(scenarios.id, forkFrom.id),
      });
      if (!scenario) {
        throw new NotFoundError(`Scenario not found: ${forkFrom.id}`);
      }
      if (scenario.status !== 'ACTIVE' && scenario.status !== 'PROMOTED') {
        throw new BusinessRuleError(
          `Cannot fork from a ${scenario.status} scenario`,
          { rule: 'INVALID_FORK_SOURCE' }
        );
      }
    }
  }

  /**
   * Validate a change before applying
   */
  private async validateChange(scenarioId: string, change: ScenarioChange): Promise<void> {
    if (change.type === 'PM_MOVE' || change.type === 'PM_REMOVE') {
      // Verify the entity exists in the materialized scenario
      const materialized = await this.materializeScenario(scenarioId);
      const exists = materialized.pmSchedule.some((pm) => pm.id === change.entityId);
      if (!exists) {
        throw new NotFoundError(
          `PM schedule entry not found in scenario: ${change.entityId}`
        );
      }
    }

    if (change.type === 'PM_ADD') {
      if (!change.newValues) {
        throw new ValidationError('PM_ADD requires newValues with trainId, pmTypeId, targetDate');
      }
      const newValues = change.newValues as Record<string, unknown>;
      if (!newValues.trainId || !newValues.pmTypeId || !newValues.targetDate) {
        throw new ValidationError('PM_ADD requires trainId, pmTypeId, and targetDate');
      }
    }

    if (change.type === 'PM_MOVE') {
      if (!change.newValues || !change.newValues.targetDate) {
        throw new ValidationError('PM_MOVE requires newValues with targetDate');
      }
    }
  }

  /**
   * Calculate PM differences between two schedules
   */
  private calculatePMDifferences(
    scheduleA: MaterializedPmRecord[],
    scheduleB: MaterializedPmRecord[]
  ): PMDifferenceSummary {
    const differences: PMDifference[] = [];
    const bMap = new Map(scheduleB.map((pm) => [pm.id, pm]));
    const aSet = new Set(scheduleA.map((pm) => pm.id));

    let added = 0;
    let removed = 0;
    let moved = 0;
    let unchanged = 0;

    // Check A against B
    for (const pmA of scheduleA) {
      const pmB = bMap.get(pmA.id);
      if (!pmB) {
        // Added in A (not in B)
        differences.push({
          pmId: pmA.id,
          trainId: pmA.trainId,
          pmTypeId: pmA.pmTypeId,
          changeType: 'ADDED',
          scenarioADate: pmA.targetDate,
        });
        added++;
      } else if (pmA.targetDate !== pmB.targetDate) {
        // Moved
        const daysDiff = differenceInDays(
          parseISO(pmA.targetDate),
          parseISO(pmB.targetDate)
        );
        differences.push({
          pmId: pmA.id,
          trainId: pmA.trainId,
          pmTypeId: pmA.pmTypeId,
          changeType: 'MOVED',
          scenarioADate: pmA.targetDate,
          scenarioBDate: pmB.targetDate,
          daysDifference: daysDiff,
        });
        moved++;
      } else {
        unchanged++;
      }
    }

    // Check for removed (in B but not in A)
    for (const pmB of scheduleB) {
      if (!aSet.has(pmB.id)) {
        differences.push({
          pmId: pmB.id,
          trainId: pmB.trainId,
          pmTypeId: pmB.pmTypeId,
          changeType: 'REMOVED',
          scenarioBDate: pmB.targetDate,
        });
        removed++;
      }
    }

    return {
      countDelta: added - removed,
      added,
      removed,
      moved,
      unchanged,
      details: differences,
    };
  }

  /**
   * Calculate man-hour differences (simplified)
   */
  private async calculateManhourDifferences(
    scheduleA: MaterializedPmRecord[],
    scheduleB: MaterializedPmRecord[]
  ): Promise<ManhourDifferenceSummary> {
    // Simplified calculation - sum assigned hours
    const totalA = scheduleA.reduce((sum, pm) => sum + (pm.assignedHours ?? 0), 0);
    const totalB = scheduleB.reduce((sum, pm) => sum + (pm.assignedHours ?? 0), 0);

    return {
      totalDelta: totalA - totalB,
      overloadedWeeksDelta: 0, // Would require more complex calculation
      scenarioATotalHours: totalA,
      scenarioBTotalHours: totalB,
      details: [],
    };
  }

  /**
   * Calculate cost differences (simplified)
   */
  private async calculateCostDifferences(
    scheduleA: MaterializedPmRecord[],
    scheduleB: MaterializedPmRecord[]
  ): Promise<CostDifferenceSummary> {
    // Simplified calculation - estimate based on hours
    const hourlyRate = 150; // Default shop rate
    const totalA = scheduleA.reduce((sum, pm) => sum + (pm.assignedHours ?? 0), 0) * hourlyRate;
    const totalB = scheduleB.reduce((sum, pm) => sum + (pm.assignedHours ?? 0), 0) * hourlyRate;

    return {
      totalDelta: totalA - totalB,
      laborDelta: totalA - totalB,
      materialDelta: 0, // Would require material cost lookup
      scenarioATotalCost: totalA,
      scenarioBTotalCost: totalB,
    };
  }

  /**
   * Increment semantic version string
   */
  private incrementVersion(currentVersion?: string | null): string {
    if (!currentVersion) {
      return '1.0.0';
    }

    const parts = currentVersion.split('.');
    if (parts.length !== 3) {
      return '1.0.0';
    }

    const [major, minor] = parts.map(Number);
    return `${major}.${minor + 1}.0`;
  }
}

