/**
 * MMS Strategic Planner Service
 *
 * Generates and maintains 1-10 year strategic plans using genetic algorithms,
 * constrained by capacity envelopes from the tactical model.
 *
 * Key responsibilities:
 * - Project PM requirements for all trains over 10-year horizon
 * - Generate quarterly constraint envelopes (track, labor, material)
 * - Run genetic algorithm to optimize PM allocations
 * - Validate plans against capacity constraints
 * - Calculate plan metrics and fitness scores
 *
 * The strategic planner creates long-term maintenance schedules that:
 * - Respect PM hierarchy (C4 satisfies C1/C2/C3)
 * - Handle dual triggers (mileage OR time)
 * - Balance workload across quarters
 * - Avoid bow-wave accumulation
 *
 * @see specs/004-domain-services.md Section 4.5
 */

import { eq, and, desc, lte, isNull } from 'drizzle-orm';
import { addDays, addMonths, addYears, differenceInDays, format } from 'date-fns';
import { BaseService } from '../lib/services/base';
import {
  pmTypes,
  pmSchedule,
  trains,
  tracks,
  manhourCapacity,
  type PmType,
} from '../lib/db/schema';
import { getRouteUtilizationService } from './route-utilization';

// =============================================================================
// Types
// =============================================================================

/** Configuration for the genetic algorithm */
export interface StrategicPlannerConfig {
  horizonYears: number;
  granularity: 'MONTHLY' | 'QUARTERLY';
  populationSize: number;
  generations: number;
  mutationRate: number;
  eliteCount: number;
}

/** Default configuration values */
export const DEFAULT_CONFIG: StrategicPlannerConfig = {
  horizonYears: 10,
  granularity: 'QUARTERLY',
  populationSize: 100,
  generations: 500,
  mutationRate: 0.1,
  eliteCount: 10,
};

/** PM requirement projected over the horizon */
export interface PMRequirement {
  id: string;
  trainId: string;
  trainNumber: string;
  fleetId: string;
  pmTypeId: string;
  pmCode: string;
  projectedDate: Date;
  projectedMileageKm: number;
  triggerType: 'MILEAGE' | 'TIME';
  confidence: 'HISTORICAL' | 'ESTIMATED';
  estimatedHours: number;
  trackType: string;
  durationDays: number;
  constraintStart: Date;
  constraintEnd: Date;
}

/** Strategic allocation result (chromosome gene) */
export interface StrategicAllocation {
  requirementId: string;
  trainId: string;
  trainNumber: string;
  pmTypeId: string;
  pmCode: string;
  targetQuarter: string; // e.g., '2028-Q2'
  targetDate: Date;
  estimatedHours: number;
  estimatedCost: number;
  depotId: string | null;
}

/** Capacity envelope for a time period */
export interface ConstraintEnvelope {
  period: Date;
  quarterKey: string;
  trackCapacity: Array<{
    trackType: string;
    availableSlotDays: number;
    depotId: string;
  }>;
  laborCapacity: Array<{
    depotId: string;
    availableHours: number;
  }>;
  materialCapacity: Record<string, number>;
  totalAvailableHours: number;
  totalTrackSlots: number;
}

/** Validation result for a strategic plan */
export interface PlanValidation {
  valid: boolean;
  violations: PlanViolation[];
  warnings: PlanWarning[];
  score: number;
}

/** A constraint violation */
export interface PlanViolation {
  type: 'TRACK_CAPACITY' | 'LABOR_CAPACITY' | 'COMPLIANCE_WINDOW' | 'BOW_WAVE';
  quarter: string;
  description: string;
  severity: number;
}

/** A warning (non-blocking) */
export interface PlanWarning {
  type: 'HIGH_UTILIZATION' | 'UNEVEN_DISTRIBUTION' | 'LATE_PM';
  quarter: string;
  description: string;
}

/** Metrics for a strategic plan */
export interface PlanMetrics {
  totalPMs: number;
  totalHours: number;
  totalCost: number;
  averageQuarterlyLoad: number;
  loadVariance: number;
  complianceRate: number;
  bowWaveRisk: number;
  utilizationBalance: number;
}

/** Complete strategic plan result */
export interface StrategicPlanResult {
  planId: string;
  generatedAt: Date;
  horizonStart: Date;

/**
 * MMS Man-hour Leveling Service
 *
 * Projects workforce requirements and generates adjustment recommendations
 * to balance workload across time periods. Prevents overload/underutilization
 * of depot maintenance resources over the tactical planning horizon.
 *
 * Key responsibilities:
 * - Calculate raw man-hour projections from PM schedule
 * - Identify overloaded and underutilized weeks
 * - Apply leveling strategies in priority order
 * - Persist projections and adjustments
 * - Support approval workflow for adjustments
 *
 * Leveling Strategies (priority order):
 * 1. ADVANCE_PM (1.1x cost, LOW risk, max 40h/week)
 * 2. DEFER_PM (1.05x cost, LOW risk, max 40h/week)
 * 3. ADD_OVERTIME (1.5x cost, NO risk, max 80h/week)
 * 4. CROSS_DEPOT (1.3x cost, MEDIUM risk, max 60h/week)
 * 5. ADD_CONTRACTOR (2.0x cost, MEDIUM risk, max 100h/week)
 * 6. MANUAL_REVIEW (flagged for high unresolvable overload)
 *
 * Utilization Targets:
 * - Target: 85%
 * - Minimum: 70% (underutilized below this)
 * - Maximum: 100% (overloaded above this)
 *
 * @see specs/004-domain-services.md Section 4.6
 */

import {
  eq,
  and,
  gte,
  lte,
  desc,
  asc,
  sql,
  inArray,
  isNull,
  or,
  count,
  type SQL,
} from 'drizzle-orm';
import {
  addDays,
  addWeeks,
  startOfWeek,
  endOfWeek,
  format,
  differenceInWeeks,
  parseISO,
  isBefore,
  isAfter,
} from 'date-fns';
import { BaseService } from '../lib/services/base';
import {
  manhourCapacity,
  manhourProjections,
  manhourAdjustments,
  pmSchedule,
  pmTypes,
  depots,
  trains,
  laborRates,
  type ManhourCapacity,
  type ManhourProjection,
  type ManhourAdjustment,
} from '../lib/db/schema';
import { NotFoundError, ValidationError, ConflictError } from '../lib/errors';

// =============================================================================
// Constants
// =============================================================================

/** Minimum utilization percentage (underutilized below this) */
const MIN_UTILIZATION = 0.7;

/** Maximum utilization percentage (overloaded above this) */
const MAX_UTILIZATION = 1.0;

/** Default base labor rate per hour (SGD) */
const DEFAULT_BASE_RATE = 85;

/** Minimum meaningful shift in hours (don't bother with tiny adjustments) */
const MIN_SHIFT_HOURS = 8;

/** Minimum overtime hours to add */
const MIN_OVERTIME_HOURS = 4;

// =============================================================================
// Types
// =============================================================================

/** Leveling strategy types */
export type AdjustmentType =
  | 'ADVANCE_PM'
  | 'DEFER_PM'
  | 'ADD_OVERTIME'
  | 'CROSS_DEPOT'
  | 'ADD_CONTRACTOR'
  | 'MANUAL_REVIEW';

/** Risk levels for adjustments */
export type RiskLevel = 'NONE' | 'LOW' | 'MEDIUM' | 'HIGH';

/** Adjustment status in workflow */
export type AdjustmentStatus = 'PROPOSED' | 'APPROVED' | 'REJECTED' | 'APPLIED';

/** Leveling strategy configuration */
export interface LevelingStrategy {
  type: AdjustmentType;
  priority: number;
  maxHoursPerWeek: number;
  costMultiplier: number;
  riskLevel: RiskLevel;
}

/** All leveling strategies in priority order */
export const LEVELING_STRATEGIES: LevelingStrategy[] = [
  { type: 'ADVANCE_PM', priority: 1, maxHoursPerWeek: 40, costMultiplier: 1.1, riskLevel: 'LOW' },
  { type: 'DEFER_PM', priority: 2, maxHoursPerWeek: 40, costMultiplier: 1.05, riskLevel: 'LOW' },
  { type: 'ADD_OVERTIME', priority: 3, maxHoursPerWeek: 80, costMultiplier: 1.5, riskLevel: 'NONE' },
  { type: 'CROSS_DEPOT', priority: 4, maxHoursPerWeek: 60, costMultiplier: 1.3, riskLevel: 'MEDIUM' },
  {
    type: 'ADD_CONTRACTOR',
    priority: 5,
    maxHoursPerWeek: 100,
    costMultiplier: 2.0,
    riskLevel: 'MEDIUM',
  },
];

/** Time period for projections */
export interface LevelingTimePeriod {
  start: Date;
  end: Date;
}

/** Required hours breakdown */
export interface RequiredHours {
  pm: number;
  corrective: number;
  overhaul: number;
  total: number;
}

/** Available hours breakdown */
export interface AvailableHours {
  regular: number;

